class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        unordered_map<char, int> charsCount;
        for (char c : chars) {
            charsCount[c]++;
        }
        int res = 0;
        for (string& word : words) {
            unordered_map<char, int> wordCount;
            for (char c : word) {
                wordCount[c]++;
            }
            bool isGood = true;
            for (auto& pair : wordCount) {
                if (pair.second > charsCount[pair.first]) {
                    isGood = false;
                    break;
                }
            }
            if (isGood) {
                res += word.size();
            }
        }
        return res;
    }
};
```
